{"code":"import json

# Load citations
with open(locals()['var_function-call-5217440467597246773'], 'r') as f:
    citations_data = json.load(f)

# Load papers text
with open(locals()['var_function-call-17872103608699006579'], 'r') as f:
    papers_data = json.load(f)

# Map title -> citation_count
citation_map = {}
for item in citations_data:
    try:
        count = int(item['citation_count'])
        citation_map[item['title']] = count
    except:
        continue

acm_citations = []
acm_titles = []

for paper in papers_data:
    filename = paper.get('filename', '')
    title = filename.replace('.txt', '')
    text = paper.get('text', '')

    # Check for ACM
    header = text[:5000]
    is_acm = False

    # Heuristics
    if "ACM" in header:
        if "Copyright" in header and "ACM" in header:
            is_acm = True
        elif "Permission to make digital or hard copies" in header and "ACM" in header:
            is_acm = True
        elif "Association for Computing Machinery" in header:
            is_acm = True
        # Check specific conference headers
        elif "UBICOMP" in header or "CHI" in header or "CSCW" in header:
             # Most of these are ACM, but let's be strict or use the presence of ACM string
             # Usually they have "ACM" in the copyright line.
             if "ACM" in header:
                 is_acm = True

    if is_acm:
        if title in citation_map:
            acm_citations.append(citation_map[title])
            acm_titles.append(title)

avg_citations = 0
if len(acm_citations) > 0:
    avg_citations = sum(acm_citations) / len(acm_citations)

print("__RESULT__:")
print(json.dumps({
    "average_citations": avg_citations,
    "count": len(acm_citations),
    "total_papers_checked": len(papers_data)
}))
"}
